# Load round 1 data
with open('data/all_raw_leads.json') as f:
    round1 = json.load(f)

# Combine all
all_leads = round1 + pp_r2 + hospice_r2 + nonprofit_r2

# Deduplicate by email (case-insensitive), keeping first occurrence
seen_emails = set()
deduped = []
dupes = 0
for lead in all_leads:
    email = (lead.get('email') or '').strip().lower()
    if not email or email == 'not_found':
        # Keep leads without emails for reference but don't include in final count
        continue
    if email in seen_emails:
        dupes += 1
        continue
    seen_emails.add(email)
    deduped.append(lead)

print(f"Total raw leads (with emails): {len([l for l in all_leads if l.get('email') and l['email'] != 'NOT_FOUND'])}")
print(f"Duplicates removed: {dupes}")
print(f"Unique leads with emails: {len(deduped)}")

# Count by segment
from collections import Counter
segs = Counter(l['segment'] for l in deduped)
print("\nBy segment:")
for seg, count in segs.most_common():
    print(f"  {seg}: {count}")

states = Counter(l['state'] for l in deduped)
print(f"\nStates covered: {len(states)}")
print("State breakdown:", dict(states.most_common(20)))

with open('data/all_leads_deduped.json', 'w') as f:
    json.dump(deduped, f, indent=2)
print(f"\nSaved {len(deduped)} unique leads to data/all_leads_deduped.json")
